param()
Set-Location "c:\ASK\MyWorkspace\sk-keys"
$d = "c:\ASK\MyWorkspace\sk-keys\dictionary\tier-5-distributed-architecture\SYD-system-design"

$gem   = [char]::ConvertFromUtf32(0x1F48E)
$bulb  = [char]::ConvertFromUtf32(0x1F4A1)
$brain = [char]::ConvertFromUtf32(0x1F9E0)
$link  = [char]::ConvertFromUtf32(0x1F517)
$star  = [char]0x2605
$empty = [char]0x2606

function Join-Lines { param([string[]]$lines) return $lines -join "`r`n" }

# These files use ISSUE/SOLUTION format, not INVENTION MOMENT
# Use the SOLUTION text as the anchor for EVOLUTION insertion
function Upgrade-SYD-Case2 {
    param([string]$filename,[string]$newYaml,[string]$solutionAnchor,[string]$evolutionText,[string]$newRelatedContent,[string]$twContent,[string]$stContent,[string]$newThinkContent)
    $fp = "$d\$filename"
    $c = [System.IO.File]::ReadAllText($fp, [System.Text.Encoding]::UTF8)
    $nl = if ($c.Contains("`r`n")) { "`r`n" } else { "`n" }
    $fmEnd = $c.IndexOf("---", 4); $afterFm = $c.Substring($fmEnd + 3); $c = $newYaml + $afterFm
    if ($c.Contains($solutionAnchor)) {
        $c = $c.Replace($solutionAnchor, $solutionAnchor + $nl + $nl + "**EVOLUTION:**" + $nl + $evolutionText)
    } else { Write-Warning "Solution anchor not found in $filename" }
    $rkHeader = "### $link Related Keywords"
    $rkPos = $c.IndexOf($rkHeader)
    if ($rkPos -ge 0) {
        $afterRk = $c.IndexOf("---", $rkPos + $rkHeader.Length)
        $c = $c.Substring(0, $rkPos) + $rkHeader + $nl + $nl + $newRelatedContent + $nl + $nl + $c.Substring($afterRk)
    } else { Write-Warning "Related Keywords not found in $filename" }
    $thinkHeader = "### $brain Think About This Before We Continue"
    $thinkPos = $c.IndexOf($thinkHeader)
    if ($thinkPos -ge 0) {
        $dashBefore = $c.LastIndexOf($nl + "---" + $nl, $thinkPos)
        $bodyPart = $c.Substring(0, $dashBefore)
        $c = $bodyPart + $nl + "---" + $nl + $nl + "### $gem Transferable Wisdom" + $nl + $nl + $twContent + $nl + $nl + "---" + $nl + $nl + "### $bulb The Surprising Truth" + $nl + $nl + $stContent + $nl + $nl + "---" + $nl + $nl + $thinkHeader + $nl + $nl + $newThinkContent + $nl
    } else { Write-Warning "Think section not found in $filename" }
    $c = $c.Replace("_Hint:_", "*Hint:*")
    [System.IO.File]::WriteAllText($fp, $c, [System.Text.Encoding]::UTF8)
    Write-Host "OK: $filename" -ForegroundColor Green
}

# ============================================================
# SYD-048 - Chat System Design
# ============================================================
$yaml048 = Join-Lines @("---","id: SYD-048","title: Chat System Design","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-047","used_by:","related: SYD-047, SYD-036, SYD-035","tags:","  - architecture","  - advanced","  - distributed","  - async","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 48","permalink: /syd/chat-system-design/","---")
$sol048 = "Persist canonical messages, stream real-time delivery when possible, and sync missed events later."
$evo048 = "Real-time chat evolved from centralised IRC servers (1988) through peer-to-peer ICQ (1996) to today's WebSocket-based distributed architectures. WhatsApp (2009) demonstrated that a lean engineering team could scale to billions of users with Erlang's actor model. Slack (2013) popularised rich presence and integrations for workplace collaboration. The architectural challenge evolved from simple message delivery to multi-device synchronisation, end-to-end encryption, rich media handling, and regulatory compliance across jurisdictions. Modern chat systems are the proving ground for distributed systems patterns: consistent messaging requires solving ordering, delivery guarantees, and presence at internet scale."
$rk048 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-047 - Notification System Design]] - core real-time delivery infrastructure that chat builds on","","**Builds On This (learn these next):**","- [[SYD-036 - Push vs Pull Architecture]] - fundamental design decision in chat message delivery","- [[SYD-035 - Fan-Out on Write vs Read]] - fan-out strategy for group chat delivery","","**Alternatives / Comparisons:**","- [[SYD-047 - Notification System Design]] - simpler one-way delivery vs chat's bidirectional model","- [[SYD-036 - Push vs Pull Architecture]] - core architectural choice within chat design")
$tw048 = Join-Lines @("**Reusable Engineering Principle:**","Delivery guarantees define user trust. Chat users expect messages to arrive exactly once, in order, and to be retrievable forever (or until deleted). These three requirements - exactly-once delivery, ordering, and durability - form the core of any messaging system design. The same trio appears in payment processing (exactly-once transactions), event sourcing (ordered event log, durable history), and distributed databases (exactly-once writes, consistent read ordering).","","**Where else this pattern appears:**","- **Payment processing:** A payment must be idempotent (exactly-once), ordered (no debit before credit), and durable (permanent record) - the same three properties as chat messages.","- **Event sourcing:** An event log must be append-only (ordered), persistent (durable), and deduplicated (exactly-once) - a chat message store under a different name.","- **Email delivery:** SMTP with deduplication IDs implements at-least-once delivery; the receiver deduplicates - the same exactly-once pattern with the dedup step at the consumer.")
$st048 = "WhatsApp served 2 billion users with fewer than 50 engineers as of 2014 - an extraordinary efficiency achieved by Erlang's actor model where each user connection is a lightweight process. Traditional Java or Python web frameworks would have required 10-100x more engineers for the same scale because Erlang was designed for telecom switch software (fault-tolerant, massively concurrent, continuously running) before it was applied to chat. The right language choice - motivated by a different domain's constraints - made billion-user scale achievable with a small team. WhatsApp is the strongest argument in software engineering that domain constraints drive better language design than general-purpose optimisation."
$think048 = Join-Lines @("**Q1.** Should message ordering be guaranteed across all devices or only within one conversation timeline?","","*Hint:* Think about what ordered across all devices requires - a global sequence number for every message in every conversation. Explore what this means for write throughput at scale and whether per-conversation ordering (sequence per conversation) vs global ordering is the correct requirement.","","**Q2.** How much presence precision does your product really need?","","*Hint:* Think about what online means at the granularity of seconds (is the user's app in focus?) vs minutes (did they open the app in the last 15 minutes?). Explore whether seconds-precision presence requires persistent connections (WebSocket) or can be approximated with periodic polling, and what the server load difference is.","","**Q3 (Design Trade-off):** A user sends 1 million messages in a chat system with end-to-end encryption (E2EE). The server cannot read message content. The user gets a new device and wants message history. Design a scheme that enables multi-device message history with E2EE.","","*Hint:* Think about where the decryption key lives - if only the sender's device has it, multi-device sync is impossible without key sharing. Explore how Signal's key exchange protocol or iMessage's per-device encryption approach solve the multi-device E2EE history problem.")
Upgrade-SYD-Case2 "SYD-048 - Chat System Design.md" $yaml048 $sol048 $evo048 $rk048 $tw048 $st048 $think048

# ============================================================
# SYD-049 - Video Streaming Design
# ============================================================
$yaml049 = Join-Lines @("---","id: SYD-049","title: Video Streaming Design","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-023","used_by:","related: SYD-024, SYD-027","tags:","  - architecture","  - advanced","  - distributed","  - performance","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 49","permalink: /syd/video-streaming-design/","---")
$sol049 = "Encode multiple renditions, segment content, and serve through geographically distributed caches."
$evo049 = "Video streaming evolved from downloading entire files (RealPlayer, 1995) through progressive download to adaptive bitrate streaming (ABR). YouTube (2005) demonstrated internet-scale video delivery was possible with commodity hardware and CDN caching. Netflix (2007-2012) pioneered ABR streaming with DASH and HLS formats, then moved to custom CDN infrastructure (Open Connect). The engineering challenge evolved from bandwidth efficiency to per-viewer adaptation, then to latency reduction for live streaming, and now to per-viewer ML-driven quality optimisation. Video streaming is responsible for approximately 70% of all internet downstream bandwidth - the largest engineering challenge in human communication history."
$rk049 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-023 - Geo-Replication]] - CDN caching is geo-replication applied to video segments","","**Builds On This (learn these next):**","- [[SYD-024 - Multi-Region Architecture]] - deployment pattern for global video CDN","- [[SYD-027 - Capacity Planning]] - video is the highest-bandwidth workload to capacity plan","","**Alternatives / Comparisons:**","- [[SYD-024 - Multi-Region Architecture]] - broader deployment pattern used for video CDN","- [[SYD-048 - Chat System Design]] - contrasting real-time design (low latency vs high throughput)")
$tw049 = Join-Lines @("**Reusable Engineering Principle:**","Segment, cache, and adapt. This three-part strategy applies beyond video: podcast streaming uses segments-and-CDN, large software updates use segmented download with resumability, and real-time data streaming (Kafka) segments data into partitioned logs that consumers read at their own pace. When content is large and networks are variable, the solution is always to segment content, cache segments close to the consumer, and adapt delivery rate to available capacity.","","**Where else this pattern appears:**","- **Software update delivery:** macOS and Windows updates are chunked into segments and delivered via CDN with delta-only downloads after the first version.","- **Podcast streaming:** RSS enclosures are served via CDN with HTTP range request support - the same segment-and-cache pattern without adaptive bitrate.","- **Kafka streaming:** Producers write to partitioned log segments; consumers read at their own pace from nearest replica - adaptive throughput via partition assignment.")
$st049 = "Video streaming's biggest engineering challenge is not bandwidth - it's time synchronisation for live events. Live streaming must deliver video frames to millions of viewers within seconds of each other (for sports, financial events, elections). The difference between a 2-second and 10-second delay determines whether viewers can discuss the same event in real time on social media. Achieving sub-5-second live streaming latency at scale requires bypassing traditional CDN caching (which introduces delays) and using low-latency protocols (LL-HLS, WebRTC). Most streaming platforms quietly accept 20-30 second delays for live events because true low latency at scale is significantly more expensive than the delay allows."
$think049 = Join-Lines @("**Q1.** What hurts more in your product: lower resolution or more buffering?","","*Hint:* Think about what product the user is actually using - sports streaming (low latency > resolution), documentary (resolution > latency), user-generated content (buffering tolerance varies). Explore whether the answer changes by content type and whether the product should offer user-configurable quality preferences.","","**Q2.** How would live video design differ from on-demand video design?","","*Hint:* Think about the fundamental difference: on-demand has the complete file available before any user starts watching (pre-encode, pre-upload to CDN), while live has only the last few seconds available at any moment. Explore what changes in the encoding pipeline, CDN strategy, and error recovery when no pre-caching is possible.","","**Q3 (Scale):** Netflix serves 50 million concurrent streams globally. A popular show launches and 2 million users start streaming the same episode simultaneously at 12:01 AM. Your CDN has 5-minute TTL on video segments. Design a pre-warming strategy that ensures smooth playback at launch.","","*Hint:* Think about what happens when 2 million cache misses simultaneously hit the origin for the same segments. Explore how pre-warming (distributing popular content to edge nodes before launch) and staggered release (soft launch with a small cohort before the public launch time) prevent the thundering herd at the CDN edge.")
Upgrade-SYD-Case2 "SYD-049 - Video Streaming Design.md" $yaml049 $sol049 $evo049 $rk049 $tw049 $st049 $think049

# ============================================================
# SYD-050 - Ride-Sharing System Design
# ============================================================
$yaml050 = Join-Lines @("---","id: SYD-050","title: Ride-Sharing System Design","category: System Design","tier: tier-5-distributed-architecture","folder: SYD-system-design","difficulty: $star$star$star","depends_on: SYD-023","used_by:","related: SYD-048, SYD-047, SYD-027","tags:","  - architecture","  - advanced","  - distributed","  - realtime","status: complete","version: 1","layout: default","parent: `"System Design`"","grand_parent: `"Technical Dictionary`"","nav_order: 50","permalink: /syd/ride-sharing-system-design/","---")
$sol050 = "Keep fresh location state, index by geography, and run dispatch logic near real time."
$evo050 = "Ride-sharing emerged from GPS-enabled smartphones (2007) making real-time location sharing practical at consumer scale. Uber (2009) and Lyft (2012) demonstrated that a marketplace matching model - riders bidding for supply dynamically - outperformed fixed-price taxi dispatch. The engineering challenge evolved from basic location tracking to surge pricing algorithms, ETA prediction with traffic, and fraud detection at marketplace scale. The discipline absorbed techniques from computational geometry (geospatial indexing), operations research (optimal matching under uncertainty), and real-time systems (sub-second dispatch latency). Modern ride-sharing platforms are simultaneously logistics systems, financial systems, and real-time two-sided marketplaces."
$rk050 = Join-Lines @("**Prerequisites (understand these first):**","- [[SYD-023 - Geo-Replication]] - location data requires geographically distributed storage and indexing","","**Builds On This (learn these next):**","- [[SYD-048 - Chat System Design]] - in-app messaging between driver and rider","- [[SYD-047 - Notification System Design]] - trip status and driver arrival notifications","- [[SYD-027 - Capacity Planning]] - capacity planning for geospatial query load at peak","","**Alternatives / Comparisons:**","- [[SYD-048 - Chat System Design]] - contrasting real-time design (bidirectional messaging vs location matching)","- [[SYD-047 - Notification System Design]] - complementary notification layer for trip lifecycle events")
$tw050 = Join-Lines @("**Reusable Engineering Principle:**","Index data by the dimension you query most. Traditional relational databases cannot efficiently answer find all drivers within 500 meters - the query requires scanning all drivers. Geospatial indexes (QuadTree, S2 cells, PostGIS) answer proximity queries in O(log n). This same principle applies to time-series data (index by timestamp, not user ID), log data (index by event type, not payload), and product search (index by attribute facets, not product description text).","","**Where else this pattern appears:**","- **Time-series databases:** InfluxDB and TimescaleDB index data by time first - the primary query dimension. Non-time-indexed databases perform full scans for time-range queries.","- **Geospatial search:** Elasticsearch's geo-distance queries use geohash buckets to quickly find points within a radius - the same QuadTree principle as ride-sharing dispatch.","- **Recommendation systems:** User-item matrix is indexed by user ID for fast recommendation lookup - index by the query dimension (user) not the item dimension.")
$st050 = "Uber's early matching system was trivially simple: find the nearest driver and assign them. As Uber scaled, they discovered that nearest-driver matching produced globally suboptimal outcomes - it would match a rider to a driver 2 minutes away while a driver 4 minutes away was positioned to serve 5 future riders the system could predict. The matching problem evolved from a greedy local optimisation to a batched global optimisation running at 500ms intervals - assigning multiple riders to multiple drivers simultaneously for the globally minimum expected wait time. The upgrade from greedy to batch optimisation increased driver earnings by 15% without adding any new drivers - the same supply became more valuable through smarter allocation."
$think050 = Join-Lines @("**Q1.** Should dispatch optimize primarily for ETA, driver fairness, or marketplace efficiency?","","*Hint:* Think about the tension between ETA (user experience: get the ride fast), driver fairness (driver income: each driver gets equal work), and marketplace efficiency (platform economics: maximise completed trips per driver-hour). Explore whether a single objective function can capture all three or whether multi-objective optimisation with weights is necessary.","","**Q2.** How would you reduce incorrect matches caused by stale location updates?","","*Hint:* Think about what stale location means for the matching algorithm: if a driver's last known location is 30 seconds old, where are they now? Explore whether you can predict the driver's current position from their velocity and heading, and what threshold of location staleness makes a match incorrect.","","**Q3 (Scale):** During a major event (New Year's Eve), demand spikes 10x and supply remains flat. Surge pricing kicks in. Design the surge pricing algorithm such that it increases supply (incentivises more drivers to come online) without causing rider churn (pricing out most users).","","*Hint:* Think about surge pricing as a two-sided marketplace signal: it must simultaneously incentivise supply and rationally ration demand. Explore whether a capped surge multiplier (1.0-2.5x) vs uncapped surge balances the dual objective, and how real-time driver-online-response data would inform the algorithm.")
Upgrade-SYD-Case2 "SYD-050 - Ride-Sharing System Design.md" $yaml050 $sol050 $evo050 $rk050 $tw050 $st050 $think050

Write-Host "`nBatch 3 (SYD-048 to SYD-050) complete." -ForegroundColor Cyan
